import scala.xml._
import javax.ws.rs._

@Path("/config")
class ConfigService {

  @POST
  @Consumes(Array(MediaType.TEXT_XML))
  @Produces(Array(MediaType.APPLICATION_JSON))
  def parseConfig(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    extractSettings(xml)
  }

  private def extractSettings(node: Node): Map[String, String] = {
    node.child.collect {
      case e: Elem if e.label == "setting" =>
        (e \@ "key") -> (e.text.trim.replaceAll("&amp;", "&").replaceAll("&lt;", "<").replaceAll("&gt;", ">"))
    }.toMap
  }
}